var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"조립은 끝났어.","JPN":"組み立ては終わったよ。","ENG":"It's finished. The assembly is complete.","TWN":"組裝已經完成了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"마왕 타기리온.","JPN":"魔王タギリオン。","ENG":"Demon Lord Thagirion.","TWN":"魔王塔基里翁。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DOLL_ANAP_NO_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"DOLL_ANAP_NO_NAME","text":{"KOREA":"이 모습은...?","JPN":"この姿は……？","ENG":"This form...?","TWN":"這個是……？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"기억나? 우리가 가장 행복했던 어린 시절의 모습을.","JPN":"覚えてる？　私たちが一番幸せだった、子どもの頃の姿。","ENG":"Do you remember? The way we looked as children, back when we were happiest.","TWN":"你還記得嗎？我們最幸福的童年模樣。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"DOLL_ANAP_NO_NAME","text":{"KOREA":"...그래. 기억나.","JPN":"……うん、覚えてる。","ENG":"...Yes. I remember.","TWN":"……是的，我記得。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"DOLL_ANAP_NO_NAME","text":{"KOREA":"처음으로 인형을 자랑했더니, 언니는 이렇게 예쁘면 팔아도 되겠다는 말을 했었지.","JPN":"初めて作った人形を自慢したら、お姉ちゃんは売り物にできるほど可愛いと言ってくれたよね。","ENG":"When I showed you the doll I made for the first time, you said it was so beautiful I could probably sell it.","TWN":"我第一次誇獎那個人偶，結果姐姐說這麼漂亮的話，應該也可以賣掉吧。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그래서 파는 게 아니라 생일선물이라고 했더니, 화들짝 놀라면서 당황했잖아.","JPN":"それで売り物じゃなくて誕生日プレゼントって言ったら、びっくりして慌ててた。","ENG":"So I told you it wasn't for sale. It was a birthday present. You were so startled and flustered.","TWN":"所以你不是嚇了一跳，慌張地說那不是要賣的，而是生日禮物嗎？"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"DOLL_ANAP_NO_NAME","text":{"KOREA":"...언니는 그런 모습, 원래 잘 안 보여주는데 말이야.","JPN":"……お姉ちゃんはそんな姿、めったに見せないのに。","ENG":"...You don't usually show that side of yourself.","TWN":"……姐姐本來就很少露出那種表情。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그때... 인형을 팔아서 언니를 부자로 만들어줄거라 다짐하고 연습했는데...","JPN":"あの時……人形を売ってお姉ちゃんを大富豪にしてあげようと思って、頑張って練習したけど……","ENG":"Back then... I practiced because I promised I'd sell dolls and make you rich someday...","TWN":"那時……我曾下定決心要賣掉人偶，讓姐姐變得富有，還練習了很多次……"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"널 만드는 데에 쓰게 될 줄은 몰랐네.","JPN":"その腕を、あなたを作るために使うことになるとは。","ENG":"I never thought I'd end up using those skills to make you.","TWN":"沒想到最後卻用在了創造你。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"DOLL_ANAP_NO_NAME","text":{"KOREA":"그런 말하지 마.","JPN":"そんなこと言わないで。","ENG":"Don't say that.","TWN":"別那樣說。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"DOLL_ANAP_NO_NAME","text":{"KOREA":"이 모습은, 지금까지 만든 그 어떤 인형보다 아름다워.","JPN":"この姿は、今まで作ったどの人形よりも美しいよ。","ENG":"This form is more beautiful than any doll I've ever made.","TWN":"這個樣子，比迄今製作的任何人偶都還要美麗。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"...미안해. 너에게 이런 나쁜 역할을 맡겨서.","JPN":"……ごめんね。あなたにこんな悪役を任せてしまって。","ENG":"...I'm sorry. For making you take on such a terrible role.","TWN":"……對不起，讓你承擔這樣的角色。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"DOLL_ANAP_NO_NAME","text":{"KOREA":"누군가는 운명을 받아들이고, 또 누군가는 과거의 순수함을 간직해야 하니까.","JPN":"誰かは運命を受け入れ、誰かは過去の純粋さを保っていないといけないから。","ENG":"Someone has to accept our fate, and someone else has to preserve the innocence we once had.","TWN":"因為有人必須接受命運，也有人必須保留過去的純真。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"DOLL_ANAP_NO_NAME","text":{"KOREA":"먼 훗날, 우리의 운명을 정해준 그녀에게 복수하기 위해.","JPN":"遠い未来、私たちの運命を決めた彼女に復讐するために。","ENG":"So that one day, far in the future, we can take revenge on the one who decided our fate.","TWN":"為了在遙遠的未來，向決定我們命運的她復仇。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_17"},{"id":"L21_1","type":"dialog","speaker":"DOLL_ANAP_NO_NAME","text":{"KOREA":"방금... 나에게 뭘 집어넣은 거야?","JPN":"今……私に何を入れたの？","ENG":"Just now... what did you put inside me?","TWN":"剛才……你在我的身體放了什麼？"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"언니를 사랑하는 나의 마음.","JPN":"お姉ちゃんを愛する私の心。","ENG":"My love for you, sister.","TWN":"我對姐姐的愛。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DOLL_ANAP_NO_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DOLL_ANAP_NO_NAME","text":{"KOREA":"처음 각오와 다르잖아, 아우드라.","JPN":"最初の覚悟と違うじゃない、アウドラ。","ENG":"That's not what we agreed on, Audra.","TWN":"這和最初的覺悟不同啊，奧德拉。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DOLL_ANAP_NO_NAME","text":{"KOREA":"이런 순수하고 나약한 마음은... 나에게 필요 없어.","JPN":"こんな純粋で弱い心は……私には要らない。","ENG":"Such pure and fragile feelings... I don't need them.","TWN":"我不需要……這種純粹而脆弱的心。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"넌 아주 오랜 시간동안 마왕으로서... 우리와 같은 운명을 가진 다른 세계의 아이들을 죽이며, 외롭게 살아갈 거야.","JPN":"あなたはこれから長い時間を魔王として……私たちと同じ運命を持つ他の世界の子を殺しながら寂しく生きていく。","ENG":"For a very long time, you'll live on as a Demon Lord... Killing children from other worlds who share the same fate as us, all alone.","TWN":"你將在很長的時間裡，作為魔王活下去……殺死來自其他世界、與我們有相同命運的孩子們，孤獨地活著。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"적어도 우리 중 한 명은 그 아이들의 최후를 사랑으로 애도하며 눈물을 흘려줘야 하니까.","JPN":"せめて私たちのどちらかは、その子の最後を愛で追悼し、涙を流してあげないといけないから。","ENG":"At the very least, one of us should mourn their ends with love and shed tears for them.","TWN":"至少我們之中必須有一個人，要流淚哀悼那些孩子的結局。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그러니까, 이 마음은 네가 간직해줬으면 좋겠어.","JPN":"だから、この心はあなたが持っていてほしい。","ENG":"So I want you to keep this feeling safe.","TWN":"所以，請你替我保留這份心意。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DOLL_ANAP_NO_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_ANAP_NO_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"만약... 내가 네가 준 이 마음을 더럽힐 만큼, 악의에 물든다면...","JPN":"もし……あなたがくれたこの心を汚すほど、私が悪意に染まったら……","ENG":"If... I become so consumed by evil that I defile the feelings you gave me...","TWN":"如果……有一天我被惡意侵蝕，玷汙了你給我的這份心意……"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그땐, 네가 나를 멈춰줘.","JPN":"その時は、あなたが私を止めてね。","ENG":"Then you must stop me.","TWN":"那時候，就由你來阻止我。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"나는 널 죽이지 않아.","JPN":"私はあなたを殺さないよ。","ENG":"I won't kill you.","TWN":"我不會殺你。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"영겁이 흐른 먼 훗날, 가을의 끝무렵 즈음에... 우리는 다시 하나로 돌아갈 테니까.","JPN":"永劫の時が流れた遠い未来、晩秋頃……私たちは再び一つになるんだから。","ENG":"Far in the distant future, near the end of autumn after an eternity has passed... we will become one again.","TWN":"在遙遠的未來，當秋天走到盡頭時……我們會再次合而為一。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"보고 있어? 타기리온?","JPN":"見えてる？　タギリオン。","ENG":"Do you see it, Thagirion?","TWN":"看見了嗎，塔基里翁？"},"stage":{"bg":"MS_1606_2","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그녀의 분신이 우리의 결실을 손에 쥐고... 우릴 이렇게 만든 자의 심장에 비수를 꽂는 광경이.","JPN":"彼女の分身が私たちが生み出した結実を手に取り……私たちをこんな目に遭わせた者の心臓を貫く光景が。","ENG":"The sight of her avatar holding the fruit we created in her hands... and driving a blade into the heart of the one who made us this way.","TWN":"她的分身手中握著我們創造的成果……將刀刃刺入將我們變成這樣的人的心臟。"},"stage":{"bg":"MS_1606_2","bgm":"THEMA_CITY_G1","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_LAMP"},{"id":"L45_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"기구하지 않나?","JPN":"どうした？","ENG":"What's wrong?","TWN":"怎麼了？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THAMIEL_NORMAL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇게 많은 이들의 최후를 보아온 신이, 정작 자신의 패배한 현실은 받아들이지 못하는 표정이라니 말이야.","JPN":"あれだけ多くの血を見てきた君が、自分の血を見て衝撃でも受けたのかね。","ENG":"You've seen the blood of so many others. Are you shocked to see your own?","TWN":"見慣了無數鮮血的你，看到自己的血就陷入衝擊了嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THAMIEL_NORMAL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_NULL","text":{"KOREA":"후후... 어리석은 내 사랑.","JPN":"ふふ……愚かな、私の愛しい人。","ENG":"Haha... My foolish love.","TWN":"呵呵……我所愛的愚笨之人。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THAMIEL_NORMAL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_NULL","text":{"KOREA":"당신은 종말 너머에 어떤 존재가 있는지, 아무것도 몰라.","JPN":"あなたは終末の向こうに何があるのか、何も知らない。","ENG":"You know nothing about what lies beyond the end.","TWN":"你根本不知道，在末日之後存在著什麼。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THAMIEL_NORMAL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_NULL","text":{"KOREA":"그곳에 있는 심연이, 무엇을 필요로 하는지도.","JPN":"そこに在る深淵が、何を求めているのかも。","ENG":"Nor what the abyss that waits there truly requires.","TWN":"你也不知道那深淵究竟需要什麼。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THAMIEL_NORMAL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"...그래.","JPN":"……ああ。","ENG":"...No.","TWN":"……嗯。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_LIFE_BEAGINS_GONE_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THAMIEL_NORMAL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"신에게는 세계를 살아가는 인간이 이해할 수 없는 신만의 고민거리가 있겠지.","JPN":"神には世界を生きる人間には理解できない、神だけの悩みがあるだろう。","ENG":"Gods must have worries of their own that humans living within the world cannot understand.","TWN":"神確實有著人類無法理解的煩惱。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_LIFE_BEAGINS_GONE_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THAMIEL_NORMAL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_LIFE_BEAGINS_GONE_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THAMIEL_NORMAL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만...!","JPN":"だが……！","ENG":"But...!","TWN":"但是……！"},"stage":{"bg":"QLIPHOTH","bgm":"THEMA_LIFE_BEAGINS_GONE_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THAMIEL_NORMAL_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BOMB_DAMAGE_DOWN"},{"id":"L11_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_NULL","text":{"KOREA":"큿...?!","JPN":"くっ……！？","ENG":"Kgh...?!","TWN":"咳……？！"},"stage":{"bg":"MS_1607","bgm":"THEMA_LIFE_BEAGINS_GONE_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THAMIEL_NORMAL_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_ABOMINATION_DAMAGE_DOWN"},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"작디작은 세상 품안에서 살아가는 대부분의 평범한 인간들에겐, 신이 바라보는 풍경 따윈 아무런 의미도 없어.","JPN":"小さい世界の中で生きる、平凡な人々には、君が見た景色がどんなものかなど知ったことではない。","ENG":"For most ordinary humans who live within the embrace of a small world, what you saw holds no meaning at all.","TWN":"對在這個渺小世界中生活的絕大多數普通人來說，無論你看到的景象是什麼，都毫無意義。"},"stage":{"bg":"MS_1607","bgm":"THEMA_LIFE_BEAGINS_GONE_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THAMIEL_NORMAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 비밀이 얼마나 끔찍한 비극이고, 추악한 진실이건-!","JPN":"それがどんなに酷い悲劇で、醜い真実であっても……！","ENG":"No matter how terrible a tragedy it is, or how ugly a truth it may be...!","TWN":"無論那是多麼可怕的悲劇、醜陋的真相—！"},"stage":{"bg":"MS_1607","bgm":"THEMA_LIFE_BEAGINS_GONE_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THAMIEL_NORMAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그것을 직면하는 건, 모든 것을 관장하는 신이 아닌 모든 것을 감내하는 인간의 역할이 되어야만 해.","JPN":"それを目にするのは、すべてを司る神ではなく、すべてに耐える人間の役目でないとならない。","ENG":"Facing it must be the role of humans who endure everything, not gods who govern everything.","TWN":"該面對這一切的，應該是承受一切的人類，而非支配一切的神。"},"stage":{"bg":"MS_1607","bgm":"THEMA_LIFE_BEAGINS_GONE_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THAMIEL_NORMAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"현 시간부로, 세피로트 나무의 권한 일부는 내 소유로 넘어왔다.","JPN":"現時刻を持って、セフィロトの権限の一部は私の所有になった。","ENG":"As of this moment, part of the authority over the Tree of Sephiroth has passed into my possession.","TWN":"自現在起，生命樹的一部分權限將歸我所有。"},"stage":{"bg":"MS_1607","bgm":"THEMA_LIFE_BEAGINS_GONE_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THAMIEL_NORMAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 권한을 행사하여, 황금나무의 뿌리에 의해 망가진 현실세계는 이전과 같은 모습으로 복원한다.","JPN":"この権限を行使し、黄金の木の根によって壊れた現実世界は元の姿に復元する。","ENG":"Exercising that authority, I will restore the Normalside damaged by the roots of the Golden Tree to how it once was.","TWN":"我將行使該權限，修復被黃金樹根系破壞的現實世界，使其恢復原貌。"},"stage":{"bg":"MS_1607","bgm":"THEMA_LIFE_BEAGINS_GONE_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THAMIEL_NORMAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 지금까지 탐미엘의 권한으로 강제된 운명들은 이제 효력이 사라진 것으로 간주하지.","JPN":"そして今までタミエルの権限で強制された運命の効力はすべて消えるものとする。","ENG":"And all the fates that were forcibly imposed by Tammiel's authority until now are hereby considered null and void.","TWN":"此外，迄今由塔米爾的權能強制的所有命運效力，將全部失效。"},"stage":{"bg":"MS_1607","bgm":"THEMA_LIFE_BEAGINS_GONE_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THAMIEL_NORMAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"더 이상 새로운 세계는 창조되지 않아. 정해진 운명으로 인한 비극도, 더 이상은 되풀이되는 일은 없을 거다.","JPN":"これ以上新しい世界は創造されない。決められた運命による悲劇が繰り返されることもないだろう。","ENG":"No new worlds will be created anymore. Nor will tragedies born from predetermined fate continue to repeat.","TWN":"不會再有新的世界被創造出來，也不會再重演既定命運所帶來的悲劇。"},"stage":{"bg":"MS_1607","bgm":"THEMA_LIFE_BEAGINS_GONE_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 현실이 하나로 국한된 이상, 엑자일러라 불리는 다른 세계의 존재 역시, 현 세계는 부정하지 않는다. 아무리 비슷한 삶을 타고난 인간도, 결국 운명이란 개념이 유효하지 않은 이 세계에선 엄연히 다른 존재가 될 테니까.","JPN":"現実が一つに限定された以上、エグザイラーと呼ばれる異世界の存在もまた、現世界は否定しない。いくら似たような人生を生きた人間であっても、運命という概念が存在しないこの世界では違う存在だからな。","ENG":"Now that reality is confined to a single world, even those from other worlds known as Exiles will no longer be rejected by this world. Even if they were born into nearly identical lives, in a world where the concept of fate no longer applies, they are ultimately separate individuals.","TWN":"在現實僅此唯一的前提下，現實世界亦不再否定有另一個被稱為流浪者的世界存在。即使是天生擁有相似生活的人類，最終在這個沒有命運概念的世界中，也將成為不同的存在。"},"stage":{"bg":"MS_1607","bgm":"THEMA_LIFE_BEAGINS_GONE_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"탐미엘의 제물이 될 새로운 늑대도, 그 희생양이 될 마왕도 이제 더는 필요 없어. 설령 그런 존재가 나타난다 해도, 그것은 신이 멋대로 정한 운명이 아닌 인간의 순수한 의지만으로 결정되어야 한다.","JPN":"タミエルの生贄となる新しいオオカミも、そのために犠牲になる魔王も要らない。たとえそのような存在が現れるとしても、それは神が勝手に決めた運命ではなく、純粋な人間の意志のみで決められるべきだ。","ENG":"There is no longer any need for a new Wolf to become Tammiel's sacrifice, nor a Demon Lord to serve as that offering. Even if such beings appear, their existence must be decided not by a fate arbitrarily imposed by a god, but by the pure will of humans themselves.","TWN":"不再需要作為塔米爾祭品的狼，也不再需要被犧牲的魔王。即使這樣的存在出現，那也將不再是神所決定的命運，而需要是由人類自身意志決定。"},"stage":{"bg":"MS_1607","bgm":"THEMA_LIFE_BEAGINS_GONE_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"신은 인간에게 그 어떤 운명도, 선택도 강제하지 못해. 인간의 운명에 어떠한 간섭도 하지 않아.","JPN":"神は人間にどんな運命も選択も強制できない。人間の運命にいかなる干渉もしない。","ENG":"Gods cannot impose any fate or choice upon humans. Nor may they interfere in human destiny in any way.","TWN":"神不再對人類強制施加任何命運或選擇，也不再干涉人類的命運。"},"stage":{"bg":"MS_1607","bgm":"THEMA_LIFE_BEAGINS_GONE_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"여기에 이견이 있다면... 지금 내가 얻은 권한을 모두 소진시켜서라도 탐미엘, 네 존재를 이 자리에서 말소하도록 하지.","JPN":"異見があるなら……今手に入れた権限を使い切ってでも、タミエル……君の存在をこの場で抹消する。","ENG":"If you object to this... then even if it costs me every last bit of authority I've gained, I will erase your existence here and now, Tammiel.","TWN":"若有異議……我會耗盡我取得的所有權限，在此徹底抹除塔米爾你的存在。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_LIFE_BEAGINS_GONE_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_LIFE_BEAGINS_GONE_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"THAMIEL_NORMAL_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_NULL","text":{"KOREA":"후후...","JPN":"ふふ……","ENG":"Haha...","TWN":"呵呵……"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_LIFE_BEAGINS_GONE_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"THAMIEL_NORMAL_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_NULL","text":{"KOREA":"내가 지금까지... 다른 늑대를 키웠네?","JPN":"私は今まで……違うオオカミを育てていたようね。","ENG":"So all this time... I've been raising a different kind of Wolf?","TWN":"我到現在為止……養了另一隻狼呢？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_LIFE_BEAGINS_GONE_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"THAMIEL_NORMAL_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_LIFE_BEAGINS_GONE_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"THAMIEL_NORMAL_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_NULL","text":{"KOREA":"이견, 없어.","JPN":"異見、ないよ。","ENG":"I have no objections.","TWN":"沒有異議。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_LIFE_BEAGINS_GONE_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"THAMIEL_NORMAL_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"...사라졌어.","JPN":"……消えた。","ENG":"...She's gone.","TWN":"……消失了。"},"stage":{"bg":"ANAPILIS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"도망친 건가?","JPN":"逃げたの？","ENG":"Did she run away?","TWN":"她逃走了嗎？"},"stage":{"bg":"ANAPILIS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"...그래. 아주 꼴사납게 도망쳤군.","JPN":"……ああ、無様な逃げ方だ。","ENG":"...Yes. She fled in a rather pathetic fashion.","TWN":"……是啊，狼狽地逃走了。"},"stage":{"bg":"ANAPILIS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"죽이진 못했지만... 애초에 죽이는 것도 곤란한 녀석이었다.","JPN":"殺すことはできなかったが……そもそも殺しても困るやつだ。","ENG":"We didn't kill her... but killing her would have been difficult from the start.","TWN":"雖然沒能殺死她……但她本來那也不是能輕易解決的存在。"},"stage":{"bg":"ANAPILIS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"탐미엘이 사라지면 그녀가 창조한 현실세계 역시 사라질 테니, 그걸 빌미로 고집을 부리지 않은 게 다행이야.","JPN":"タミエルが消えると彼女が創造した現実世界も消える。それを口実に意地を張られなくてよかったな。","ENG":"If Tammiel disappears, the Normalside she created would disappear as well, so it's fortunate she didn't stubbornly push the issue.","TWN":"一旦塔米爾消失，她創造的現實世界也會隨之消失。幸好她沒有再強行堅持。"},"stage":{"bg":"ANAPILIS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ANAPILIS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DASH_ANAP_CA_TRUE","text":{"KOREA":"...잘 해주었어요.","JPN":"……よくやってくれました。","ENG":"...You did well.","TWN":"……你做得很好。"},"stage":{"bg":"ANAPILIS","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DASH_ANAP_CA_TRUE","text":{"KOREA":"탐미엘의 사도인 당신이 상처가 벌어진 틈을 노리지 않았다면, 누구도 그녀에게서 나무의 권한을 빼앗진 못했을 거예요.","JPN":"タミエルの使徒であるあなたが、傷が開いた瞬間を狙ってくれなかったら……誰も彼女から木の権限を奪えなかったでしょう。","ENG":"If you, Tammiel's Apostle, hadn't taken advantage of the opening created by her wound, no one would have been able to take the Tree's authority from her.","TWN":"若不是你趁著塔米爾的使徒受傷時出手，沒有人能從她手中奪走樹的權限。"},"stage":{"bg":"ANAPILIS","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그녀에게 복수하는 게 목적이었을 텐데, 기대를 배반하게 되어 유감일세.","JPN":"彼女に復讐したかっただろうに、期待を裏切ることになって残念だ。","ENG":"Your goal must have been to take revenge on her, so I regret disappointing your expectations.","TWN":"你本來是為了向她復仇才來的，讓你失望了。"},"stage":{"bg":"ANAPILIS","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DASH_ANAP_CA_TRUE","text":{"KOREA":"...아뇨.","JPN":"……いいえ。","ENG":"...No.","TWN":"……不是。"},"stage":{"bg":"ANAPILIS","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DASH_ANAP_CA_TRUE","text":{"KOREA":"우리가 바라고 예언했던 완전한 낙원은, 당신의 선언을 통해 지금 막 완성된 걸요.","JPN":"私たちが望み、予言した完全な楽園は、あなたの助けによって今完成されましたから。","ENG":"The perfect Promised Land we longed for and foretold has just now been completed... with your help.","TWN":"我們所期望、所預言的完整樂園，正是在你的幫助下完成的。"},"stage":{"bg":"ANAPILIS","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"계속, 이곳에 남을 건가?","JPN":"ずっと、ここに残る気か？","ENG":"Will you remain here?","TWN":"你還會留在這裡嗎？"},"stage":{"bg":"ANAPILIS","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DASH_ANAP_CA_TRUE","text":{"KOREA":"...당신이 만든 새로운 규칙이라면, 저 같은 존재가 현실세계에 안주하더라도 아무런 문제가 없겠죠.","JPN":"……あなたが作った新しいルールなら、私のような存在が現実世界にいても何の問題にもならないでしょう。","ENG":"...Under the new rules you created, a being like me settling for the Normalside would not cause any problems.","TWN":"……若按照你所制定的新規則，即使像我這樣的存在留在現實世界，也不會有問題吧。"},"stage":{"bg":"ANAPILIS","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DASH_ANAP_CA_TRUE","text":{"KOREA":"하지만 아무리 다른 존재가 되었다고 해도... 그 세계의 나를 죽인 제가 그 빈자리를 대신 채울만큼 뻔뻔하고 싶진 않아요.","JPN":"でも、いくら違う存在になったとはいえ……その世界の自分を殺した私が同じ場所に収まるなんて、そんな図々しいことはしたくありません。","ENG":"But even if I've become a different being... I don't want to be shameless enough to take her place after killing the version of me from that world.","TWN":"但即使已經成為不同的存在……我不想厚顏無恥到填補那個，由我親手殺死的那個世界的我，所留下的空缺。"},"stage":{"bg":"ANAPILIS","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DASH_ANAP_CA_TRUE","text":{"KOREA":"지금까지 희생된 그녀들의 넋과 함께 이곳에 남는 것이, 제가 할 수 있는 유일한 속죄일 테니까요.","JPN":"今まで犠牲になった彼女たちの魂と共にここに残ることが、私にできる唯一の贖罪ですから。","ENG":"Remaining here with the spirits of the ones who were sacrificed until now... is the only atonement I can offer.","TWN":"與迄今為止犧牲的她們的靈魂一起留在這裡，是我唯一能做到的贖罪。"},"stage":{"bg":"ANAPILIS","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DASH_ANAP_CA_TRUE","text":{"KOREA":"하지만 언젠가, 당신 세계의 힘만으로 해쳐 나가지 못할 난관에 부딪힌다면...","JPN":"でもいつか、あなたの世界の力だけでは乗り越えられない壁にぶつかった時は……","ENG":"But someday, if you encounter a crisis that your world's strength alone cannot overcome...","TWN":"但若有一天，遇到即使靠你世界的力量也無法解決的難題……"},"stage":{"bg":"ANAPILIS","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DASH_ANAP_CA_TRUE","text":{"KOREA":"그때는 그곳으로 불러주세요. 저의 도움이라도 괜찮다면요.","JPN":"私の助けでも大丈夫なら、そこに呼んでください。","ENG":"Then please call for me. If my help would be of any use.","TWN":"若我的力量能派上用場的話，請再次呼喚我。"},"stage":{"bg":"ANAPILIS","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DASH_ANAP_CA_TRUE","text":{"KOREA":"아, 그러고보니...","JPN":"あ、そういえば……","ENG":"Ah, come to think of it...","TWN":"啊，對了……"},"stage":{"bg":"ANAPILIS","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"DASH_ANAP_CA_TRUE","text":{"KOREA":"돌려드려야 할 게, 남아있었네요.","JPN":"返すものが、まだありましたね。","ENG":"There's still something I need to return to you.","TWN":"還有一個東西該還給你。"},"stage":{"bg":"ANAPILIS","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_TRUE","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};